solution_code:
#include <iostream>
#include <stdexcept>

int safe_divide(int a, int b) {
    if (b == 0)
        throw std::runtime_error("division by zero");
    return a / b;
}

int main() {
    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        int a, b;
        std::cin >> a >> b;
        try {
            int q = safe_divide(a, b);
            std::cout << a << " / " << b << " = " << q << "\n";
        } catch (const std::runtime_error&) {
            std::cout << a << " / 0: division error\n";
        }
    }
    return 0;
}

