#include <iostream>
#include <stdexcept>

struct Guard {
    int& ref;
    explicit Guard(int& r) : ref(r) {}
    ~Guard() { ref--; }
};

void run_task(int& counter, bool should_throw) {
    counter++;
    Guard g(counter); // decrements when scope exits, whether or not we throw
    if (should_throw)
        throw std::runtime_error("task failed");
}

int main() {
    int counter = 0;
    bool flag;
    std::cin >> flag;
    std::cout << "counter before: " << counter << "\n";
    try {
        run_task(counter, flag == 1);
    } catch (const std::runtime_error&) {
        // swallow
    }
    std::cout << "counter after: " << counter << "\n";
    return 0;
}
